from __future__ import annotations


def integrator_dashboard_html() -> str:
    return r'''<!doctype html><html lang="ru"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1"><title>Интегратору — AI-BIT Enterprise</title><style>
:root{color-scheme:light;--bg:#f7f8fa;--surface:#fff;--line:#e6e8ec;--text:#17191c;--muted:#73777f;--accent:#5e6ad2;--critical:#b42318;--high:#d84a5f;--medium:#c47a13;--low:#247a55}*{box-sizing:border-box}body{margin:0;background:var(--bg);color:var(--text);font:14px/1.5 Inter,ui-sans-serif,-apple-system,BlinkMacSystemFont,"Segoe UI",sans-serif}main{max-width:1480px;margin:auto;padding:30px 30px 90px}.hero{display:flex;justify-content:space-between;gap:24px;align-items:flex-start;margin-bottom:20px}.eyebrow{font-size:11px;text-transform:uppercase;letter-spacing:.11em;font-weight:700;color:var(--muted)}h1{font-size:28px;margin:6px 0 6px;letter-spacing:-.035em}h2,h3{margin:0}.muted{color:var(--muted)}button,select{border:1px solid var(--line);background:#fff;color:var(--text);padding:8px 11px;border-radius:8px;cursor:pointer}.primary{background:#17191c;color:#fff;border-color:#17191c}.summary{display:grid;grid-template-columns:repeat(5,1fr);gap:12px;margin-bottom:16px}.card,.issue,.panel{background:var(--surface);border:1px solid var(--line);border-radius:12px;box-shadow:0 1px 2px rgba(17,24,39,.03)}.card{padding:17px}.metric{font-size:30px;font-weight:760;margin-top:8px}.toolbar{display:flex;gap:8px;flex-wrap:wrap;margin:16px 0}.layout{display:grid;grid-template-columns:280px minmax(0,1fr);gap:14px}.panel{padding:16px;height:max-content;position:sticky;top:12px}.source{display:flex;justify-content:space-between;padding:9px 0;border-bottom:1px solid #eff0f2}.source:last-child{border:0}.dot{width:8px;height:8px;border-radius:50%;background:#c7cad1}.dot.ok{background:#1f9d68}.issue{padding:17px 18px;margin-bottom:11px;border-left:4px solid var(--medium)}.issue.critical{border-left-color:var(--critical)}.issue.high{border-left-color:var(--high)}.issue.low{border-left-color:var(--low)}.issue-head{display:flex;justify-content:space-between;gap:16px}.badge{font-size:11px;font-weight:700;text-transform:uppercase;border-radius:999px;padding:4px 8px;background:#f2f3f5;color:#555b64;white-space:nowrap}.badge.critical{background:#fee4e2;color:var(--critical)}.badge.high{background:#ffeaed;color:#b4233c}.badge.medium{background:#fff4df;color:#9a5c08}.badge.low{background:#e8f7f0;color:#176b49}.module{font-size:12px;color:var(--accent);font-weight:700;margin-bottom:5px}.finding{font-size:15px;margin:10px 0}.grid{display:grid;grid-template-columns:1fr 1fr;gap:10px;margin-top:12px}.box{padding:12px;border-radius:9px;background:#fafafb;border:1px solid #eceef1}.box b{display:block;font-size:12px;margin-bottom:5px}.evidence{margin:7px 0 0;padding-left:18px;color:#50555d}.footer{display:flex;justify-content:space-between;gap:10px;margin-top:12px;padding-top:10px;border-top:1px solid #eff0f2;font-size:12px;color:var(--muted)}.empty{padding:34px;text-align:center;background:#fff;border:1px solid var(--line);border-radius:12px}@media(max-width:950px){.summary{grid-template-columns:repeat(2,1fr)}.layout{grid-template-columns:1fr}.panel{position:static}.grid{grid-template-columns:1fr}}@media(max-width:600px){main{padding:20px 14px 70px}.hero{display:block}.hero button{margin-top:12px}.summary{grid-template-columns:1fr}}
</style></head><body><main><div class="hero"><div><div class="eyebrow">Technical Workbench</div><h1>Интегратору</h1><div class="muted">Технические отклонения, доказательства, исправления и критерии повторной проверки.</div></div><button id="refresh" class="primary">Обновить диагностику</button></div><div id="summary" class="summary"></div><div class="toolbar"><select id="severity"><option value="all">Все уровни</option><option value="critical">Критичные</option><option value="high">Высокие</option><option value="medium">Средние</option><option value="low">Низкие</option></select><select id="module"><option value="all">Все модули</option></select></div><div class="layout"><aside class="panel"><h3>Источники</h3><div id="sources" style="margin-top:10px"></div><p id="principle" class="muted" style="margin-top:14px"></p></aside><section id="issues"><div class="empty">Загрузка технической диагностики…</div></section></div></main><script>
const $=s=>document.querySelector(s);const esc=v=>String(v??'').replace(/[&<>"']/g,c=>({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'}[c]));let data=null;const severityNames={critical:'Критично',high:'Высокий',medium:'Средний',low:'Низкий'};
function render(){if(!data)return;const s=data.summary||{};$('#summary').innerHTML=[['Всего',s.total||0,''],['Критичных',s.critical||0,'critical'],['Высоких',s.high||0,'high'],['Средних',s.medium||0,'medium'],['Модулей',s.modules||0,'']].map(x=>`<div class="card"><div class="muted">${x[0]}</div><div class="metric ${x[2]}">${x[1]}</div></div>`).join('');const modules=[...new Set((data.issues||[]).map(x=>x.module))].sort();$('#module').innerHTML='<option value="all">Все модули</option>'+modules.map(x=>`<option>${esc(x)}</option>`).join('');$('#sources').innerHTML=Object.entries(data.sources||{}).map(([k,v])=>`<div class="source"><span>${esc(k)}</span><span class="dot ${v?'ok':''}"></span></div>`).join('');$('#principle').textContent=data.principle||'';filter()}
function filter(){if(!data)return;const sev=$('#severity').value,mod=$('#module').value;const rows=(data.issues||[]).filter(x=>(sev==='all'||x.severity===sev)&&(mod==='all'||x.module===mod));$('#issues').innerHTML=rows.length?rows.map(x=>`<article class="issue ${esc(x.severity)}"><div class="issue-head"><div><div class="module">${esc(x.module)}</div><h3>${esc(x.title)}</h3></div><span class="badge ${esc(x.severity)}">${esc(severityNames[x.severity]||x.severity)}</span></div><div class="finding">${esc(x.finding)}</div><div class="grid"><div class="box"><b>Что исправить</b>${esc(x.fix)}</div><div class="box"><b>Как проверить</b>${esc(x.verification)}</div></div>${(x.evidence||[]).length?`<div class="box" style="margin-top:10px"><b>Доказательства</b><ul class="evidence">${x.evidence.map(e=>`<li>${esc(e)}</li>`).join('')}</ul></div>`:''}<div class="footer"><span>Источник: ${esc(x.source)}</span><span>${x.confidence!=null?'Уверенность: '+esc(x.confidence)+'%':''}</span></div></article>`).join(''):'<div class="empty">Подтверждённых отклонений по выбранному фильтру нет.</div>'}
async function load(){const b=$('#refresh');b.disabled=true;b.textContent='Обновляю…';try{const r=await fetch('/integrator-diagnostics/latest?_='+Date.now(),{cache:'no-store'});if(!r.ok)throw new Error(await r.text());data=await r.json();render()}catch(e){$('#issues').innerHTML='<div class="empty">Ошибка загрузки: '+esc(e.message)+'</div>'}finally{b.disabled=false;b.textContent='Обновить диагностику'}}$('#severity').onchange=filter;$('#module').onchange=filter;$('#refresh').onclick=load;load();
</script></body></html>'''
